var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"MONTAGNE_ADMIN_NULL_NPC","text":{"KOREA":"조금 진정됐어?","JPN":"少しは落ち着いたか？","ENG":"Feeling better?","TWN":"冷靜下來了嗎？"},"stage":{"bg":"TRAIL","bgm":"THEMA_SECURITY_AGENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MONTAGNE_ADMIN_NULL_NPC","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"MONTAGNE_ADMIN_NULL_NPC","text":{"KOREA":"마셔. 술이라고 있는 게 순 보드카뿐이더군.","JPN":"飲め。ここにはウォッカしかないみたいだが。","ENG":"Here. Vodka was the only drink I could find.","TWN":"喝吧，我只找到伏特加。"},"stage":{"bg":"TRAIL","bgm":"THEMA_SECURITY_AGENT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"MONTAGNE_ADMIN_NULL_NPC","face":"UNIT_IDLE"}}}},{"id":"L6_1","type":"dialog","speaker":"AGENT_GRONIA_NULL_NULL","text":{"KOREA":"몽타뉴.","JPN":"モンターニュ。","ENG":"Montagne.","TWN":"蒙塔妮。"},"stage":{"bg":"TRAIL","bgm":"THEMA_SECURITY_AGENT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MONTAGNE_ADMIN_NULL_NPC","face":"UNIT_IDLE"}}}},{"id":"L7_1","type":"dialog","speaker":"MONTAGNE_ADMIN_NULL_NPC","text":{"KOREA":"술 마셔도 되는 나이냐고 묻지는 마.","JPN":"酒を飲める歳かどうかは聞くな。","ENG":"Don't ask if I'm of legal age to drink.","TWN":"不要問我的年紀可以喝酒嗎。"},"stage":{"bg":"TRAIL","bgm":"THEMA_SECURITY_AGENT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MONTAGNE_ADMIN_NULL_NPC","face":"UNIT_IDLE"}}}},{"id":"L8_1","type":"dialog","speaker":"MONTAGNE_ADMIN_NULL_NPC","text":{"KOREA":"외견은 이래도 일단은 성인이야. 동면 조치 중에도 시간은 흐르거든.","JPN":"見た目はともかく一応成人だ。冬眠中でも時間は流れる。","ENG":"I might look like this, but I'm an adult. Time passes even when you're frozen in cryostasis.","TWN":"別看我長這樣，我已經是成年人了，畢竟在冬眠時時間也不會因此停止。"},"stage":{"bg":"TRAIL","bgm":"THEMA_SECURITY_AGENT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MONTAGNE_ADMIN_NULL_NPC","face":"UNIT_IDLE"}}}},{"id":"L10_1","type":"dialog","speaker":"AGENT_GRONIA_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"TRAIL","bgm":"THEMA_SECURITY_AGENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"AGENT_GRONIA_NULL_NULL","text":{"KOREA":"그래. 네가 여기서 나타나도 이상하지 않긴 하네.","JPN":"そう。君がここで現れてもおかしくはないよね。","ENG":"Right. I guess it's not so weird that you're here.","TWN":"也是，你在這裡出現沒什麼好奇怪的。"},"stage":{"bg":"TRAIL","bgm":"THEMA_SECURITY_AGENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"MONTAGNE_ADMIN_NULL_NPC","text":{"KOREA":"헛소리를 하는군. 당연히 이상하지.","JPN":"ふざけたことを。何がおかしくないだ。","ENG":"Nonsense. Of course it's weird.","TWN":"你在說什麼？很奇怪吧。"},"stage":{"bg":"TRAIL","bgm":"THEMA_SECURITY_AGENT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MONTAGNE_ADMIN_NULL_NPC","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"MONTAGNE_ADMIN_NULL_NPC","text":{"KOREA":"벌레처럼 죽이려 들더니 이딴 열차에 처박아 둔다고?","JPN":"私を虫のように殺そうとしてきたと思えば、こんな列車に閉じ込めて。","ENG":"First you try to kill me like I'm some bug, and now you stick me in a crappy train?","TWN":"你之前明明恨不得把我殺掉，現在卻把我塞進這麼一台列車裡？"},"stage":{"bg":"TRAIL","bgm":"THEMA_SECURITY_AGENT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MONTAGNE_ADMIN_NULL_NPC","face":"UNIT_IDLE"}}}},{"id":"L16_1","type":"dialog","speaker":"MONTAGNE_ADMIN_NULL_NPC","text":{"KOREA":"충분히 가지고 놀지 못한 게 얼마나 강한 인상이 들었길래?","JPN":"私で遊び尽くせなかったことが、そんなに悔しかったのか？","ENG":"Were you holding a grudge from not harassing me enough?","TWN":"沒能盡情玩弄我是給你留下多大的遺憾？"},"stage":{"bg":"TRAIL","bgm":"THEMA_SECURITY_AGENT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MONTAGNE_ADMIN_NULL_NPC","face":"UNIT_IDLE"}}}},{"id":"L17_1","type":"dialog","speaker":"AGENT_GRONIA_NULL_NULL","text":{"KOREA":"마에스트로가 아니라, 나 때문이겠지.","JPN":"きっとマエストロじゃなくて、私のせいね。","ENG":"It's probably because of me, not Maestra.","TWN":"不是指揮家，是因為我的關係吧。"},"stage":{"bg":"TRAIL","bgm":"THEMA_SECURITY_AGENT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"MONTAGNE_ADMIN_NULL_NPC","face":"UNIT_IDLE"}}}},{"id":"L18_1","type":"dialog","speaker":"AGENT_GRONIA_NULL_NULL","text":{"KOREA":"네 말이 맞았어. 레아 슈나이더는 네퀴티아였으니까.","JPN":"君の言ったとおりだった。レア・シュナイダーはネキティアだったよ。","ENG":"You were right. Because Leah Schneider was Nequitia.","TWN":"不過你說的也沒錯，因為蕾亞·修奈德就是莉奎蒂亞。"},"stage":{"bg":"TRAIL","bgm":"THEMA_SECURITY_AGENT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MONTAGNE_ADMIN_NULL_NPC","face":"UNIT_IDLE"}}}},{"id":"L19_1","type":"dialog","speaker":"MONTAGNE_ADMIN_NULL_NPC","text":{"KOREA":"술이 들어가니 말이 통하는군.","JPN":"酒が入って、やっと話が通じたか。","ENG":"The vodka's helping you open up, I see.","TWN":"喝了酒後，終於能正常對話了。"},"stage":{"bg":"TRAIL","bgm":"THEMA_SECURITY_AGENT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MONTAGNE_ADMIN_NULL_NPC","face":"UNIT_IDLE"}}}},{"id":"L20_1","type":"dialog","speaker":"MONTAGNE_ADMIN_NULL_NPC","text":{"KOREA":"진즉 그렇게 나왔으면 서로 피곤할 것 없었잖아.","JPN":"最初からそうだったら、お互い楽だったのに。","ENG":"It could've saved us a lot of time if you started out like that.","TWN":"你早這麼說的話，我們也不需要彼此折磨。"},"stage":{"bg":"TRAIL","bgm":"THEMA_SECURITY_AGENT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MONTAGNE_ADMIN_NULL_NPC","face":"UNIT_IDLE"}}}},{"id":"L21_1","type":"dialog","speaker":"AGENT_GRONIA_NULL_NULL","text":{"KOREA":"나는 아무것도 몰랐어. 이렇게 말한다고 네가 납득할 리 없겠지만.","JPN":"私は何も知らなかったの。それを今更言ったところで君は納得しないだろうけど。","ENG":"I wasn't aware. Not that I expect you to believe me, though.","TWN":"你可能無法接受，但我那時候真的什麼都不知道。"},"stage":{"bg":"TRAIL","bgm":"THEMA_SECURITY_AGENT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MONTAGNE_ADMIN_NULL_NPC","face":"UNIT_IDLE"}}}},{"id":"L23_1","type":"dialog","speaker":"MONTAGNE_ADMIN_NULL_NPC","text":{"KOREA":"알아. 네가 몰랐다는 거.","JPN":"お前が何も知らないということはわかっていた。","ENG":"I know that you weren't aware.","TWN":"我知道你不知道。"},"stage":{"bg":"TRAIL","bgm":"THEMA_SECURITY_AGENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MONTAGNE_ADMIN_NULL_NPC","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"MONTAGNE_ADMIN_NULL_NPC","text":{"KOREA":"하지만 그걸 인정해 버리면 죽어 버린 내 전우들은?","JPN":"でもそれを認めてしまったら、死んでしまった私の戦友はどうなる？","ENG":"But if I admit that, what about my dead comrades?","TWN":"只是要是我承認的話，我那些犧牲的戰友情何以堪？"},"stage":{"bg":"TRAIL","bgm":"THEMA_SECURITY_AGENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MONTAGNE_ADMIN_NULL_NPC","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"MONTAGNE_ADMIN_NULL_NPC","text":{"KOREA":"돼지 흉내를 내면서 기어다니다가 죽은 우리 오빠는?","JPN":"豚よろしく四足で這いまわったあげく殺された兄さんは？","ENG":"What about my brother, who died after crawling on the floor like a pig?","TWN":"我那模仿豬在地上爬後死去的哥哥又該情何以堪？"},"stage":{"bg":"TRAIL","bgm":"THEMA_SECURITY_AGENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MONTAGNE_ADMIN_NULL_NPC","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"MONTAGNE_ADMIN_NULL_NPC","text":{"KOREA":"그 사람들은 누구를 원망해야 했지?","JPN":"あの人たちは誰を恨めばいい？","ENG":"Who were they supposed to blame?","TWN":"那些人該怨誰才好？"},"stage":{"bg":"TRAIL","bgm":"THEMA_SECURITY_AGENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MONTAGNE_ADMIN_NULL_NPC","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"AGENT_GRONIA_NULL_NULL","text":{"KOREA":"알아. 네가 어쩔 수 없었다는 거.","JPN":"わかってるよ。君には他にどうしようもなかったのは。","ENG":"I know. You had no choice.","TWN":"我知道，你也是有苦衷的。"},"stage":{"bg":"TRAIL","bgm":"THEMA_SECURITY_AGENT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"MONTAGNE_ADMIN_NULL_NPC","face":"UNIT_IDLE"}}}},{"id":"L30_1","type":"dialog","speaker":"AGENT_GRONIA_NULL_NULL","text":{"KOREA":"……아니. 어쩔 수 없었다고 해야만 한다는 거.","JPN":"……いいえ。どうしようもないって言うしかなかったのは。","ENG":"...Or that you have to say you had no choice.","TWN":"……不對，是必須有不得已的苦衷。"},"stage":{"bg":"TRAIL","bgm":"THEMA_SECURITY_AGENT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"MONTAGNE_ADMIN_NULL_NPC","face":"UNIT_IDLE"}}}},{"id":"L31_1","type":"dialog","speaker":"AGENT_GRONIA_NULL_NULL","text":{"KOREA":"나도 자크에게 방아쇠를 당긴 일은 그렇게 묻어 버렸으니까.","JPN":"私もジャックを撃った事実をそうやって葬ったから。","ENG":"That's how I covered the incident when I pulled the trigger on Jacques.","TWN":"畢竟我也有隱藏對札克開槍的事。"},"stage":{"bg":"TRAIL","bgm":"THEMA_SECURITY_AGENT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MONTAGNE_ADMIN_NULL_NPC","face":"UNIT_IDLE"}}}},{"id":"L33_1","type":"dialog","speaker":"MONTAGNE_ADMIN_NULL_NPC","text":{"KOREA":"술맛 떨어지는 소리는 집어치우지.","JPN":"酒がまずくなる。しけた話はそれくらいにしろ。","ENG":"This is unappetizing. Let's move on.","TWN":"別說這些掃興的話。"},"stage":{"bg":"TRAIL","bgm":"THEMA_SECURITY_AGENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MONTAGNE_ADMIN_NULL_NPC","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"MONTAGNE_ADMIN_NULL_NPC","text":{"KOREA":"네 일행이라면 다음 객차에서 기다리고 있어.","JPN":"お前の仲間なら次の客車で待っている。","ENG":"Your companion is waiting for you on the next passenger car.","TWN":"你的同伴在下一節車廂等你。"},"stage":{"bg":"TRAIL","bgm":"THEMA_SECURITY_AGENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MONTAGNE_ADMIN_NULL_NPC","face":"UNIT_IDLE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"MONTAGNE_ADMIN_NULL_NPC","text":{"KOREA":"그리고 나는 너 같은 괴물에게 응원 따위 해 주고 싶지 않아. 썩 꺼져 버려.","JPN":"それから私はお前のような化け物の応援なんてしたくない。さっさと消えてくれ。","ENG":"And I'd rather not cheer on a monster like you. Get lost.","TWN":"我可不想替你這種怪物加油，你滾吧。"},"stage":{"bg":"TRAIL","bgm":"THEMA_SECURITY_AGENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MONTAGNE_ADMIN_NULL_NPC","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"AGENT_GRONIA_NULL_NULL","text":{"KOREA":"아니. 응원이라면 널 봤을 때 이미 충분히 받았어.","JPN":"いいえ。応援なら君の顔が見られただけで十分。","ENG":"No. Seeing you was enough of a cheer for me.","TWN":"不需要，你的出現就對我而言就是一種加油。"},"stage":{"bg":"TRAIL","bgm":"THEMA_SECURITY_AGENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"AGENT_GRONIA_NULL_NULL","text":{"KOREA":"너는 내가 여기 있는 이유야.","JPN":"君がいたから私はここにいられるの。","ENG":"You're the reason I'm here.","TWN":"你就是我來到這裡的原因。"},"stage":{"bg":"TRAIL","bgm":"THEMA_SECURITY_AGENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"AGENT_GRONIA_NULL_NULL","text":{"KOREA":"그렇게 시달렸는데도, 결국 나는 널 죽이지 않았으니까.","JPN":"あんなに恨まれることをしたのに、結局君は私を殺さなかったんだから。","ENG":"Even after struggling that much, I didn't kill you in the end.","TWN":"因為我們糾纏這麼久，我最後還是沒有選擇殺掉你。"},"stage":{"bg":"TRAIL","bgm":"THEMA_SECURITY_AGENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"MONTAGNE_ADMIN_NULL_NPC","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"TRAIL","bgm":"THEMA_SECURITY_AGENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MONTAGNE_ADMIN_NULL_NPC","face":"UNIT_IDLE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"AGENT_GRONIA_NULL_NULL","text":{"KOREA":"동작 그만.","JPN":"そこまでよ。","ENG":"Don’t move.","TWN":"住手。"},"stage":{"bg":"PROLOGUE_04","bgm":"THEMA_SECURITY_AGENT","filter":"NCFT_SEPIA","slots":{"L":{"char_id":"MONTAGNE_ADMIN_NULL_NPC","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L42_1","type":"dialog","speaker":"AGENT_GRONIA_NULL_NULL","text":{"KOREA":"다시 만나서 반가워, 저격수. 몽타뉴라고 했던가.","JPN":"また会えてうれしいね、スナイパー。モンターニュって名前だっけ。","ENG":"Nice to see you again, sniper. You said your name was... Montagne?","TWN":"終於又見面了。狙擊手蒙塔妮。"},"stage":{"bg":"PROLOGUE_04","bgm":"THEMA_SECURITY_AGENT","filter":"NCFT_SEPIA","slots":{"L":{"char_id":"MONTAGNE_ADMIN_NULL_NPC","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L43_1","type":"dialog","speaker":"AGENT_GRONIA_NULL_NULL","text":{"KOREA":"손 들고 이쪽으로 돌아서.","JPN":"手を上げてこっちを向いて。","ENG":"Put your hands up and turn this way.","TWN":"舉起手到這邊來。"},"stage":{"bg":"PROLOGUE_04","bgm":"THEMA_SECURITY_AGENT","filter":"NCFT_SEPIA","slots":{"L":{"char_id":"MONTAGNE_ADMIN_NULL_NPC","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L45_1","type":"dialog","speaker":"MONTAGNE_ADMIN_NULL_NPC","text":{"KOREA":"……완전히 읽혔군.","JPN":"……完全に読まれたか。","ENG":"...You predicted this completely.","TWN":"……看來完全被你識破了。"},"stage":{"bg":"PROLOGUE_04","bgm":"THEMA_SECURITY_AGENT","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"MONTAGNE_ADMIN_NULL_NPC","face":"UNIT_IDLE"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"AGENT_GRONIA_NULL_NULL","text":{"KOREA":"다행히도 말이야.","JPN":"……幸いにね。","ENG":"Fortunately, yes.","TWN":"是的，挺幸運的不是嗎。"},"stage":{"bg":"PROLOGUE_04","bgm":"THEMA_SECURITY_AGENT","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"AGENT_GRONIA_NULL_NULL","text":{"KOREA":"오빠를 떠내보낸 건 안타깝지만, 우리는 네가 복수해야 할 상대가 아냐.","JPN":"お兄さんが死んだのは気の毒だけど、私たちは君の仇討の相手じゃないよ。","ENG":"It truly is regrettable about what happened to your brother, but we’re not the right targets for your revenge.","TWN":"雖然你失去哥哥很可憐，但我們不是你要復仇的物件。"},"stage":{"bg":"PROLOGUE_04","bgm":"THEMA_SECURITY_AGENT","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"AGENT_GRONIA_NULL_NULL","text":{"KOREA":"무기 내려 놓고 손 들어. 묵비권을 행사할 권리는 있을 거야.","JPN":"武器を下ろして手を上げて。黙秘権を行使する権利はあるはずだろうね。","ENG":"Drop your weapon and put your hands up. You have the right to remain silent, probably.","TWN":"放下武器，舉起手來。你有權保持沉默。"},"stage":{"bg":"PROLOGUE_04","bgm":"THEMA_SECURITY_AGENT","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"MONTAGNE_ADMIN_NULL_NPC","text":{"KOREA":"반역자란 녀석이…… 아직도 공작원 행세인가? 웃기는군.","JPN":"反逆者ってやつが……まだ工作員のつもり？　笑える。","ENG":"Treacherous bastard... Are you still pretending to be an operative? That’s hilarious.","TWN":"你這個叛國者……還以為自己是特工嗎？真可笑。"},"stage":{"bg":"PROLOGUE_04","bgm":"THEMA_SECURITY_AGENT","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"MONTAGNE_ADMIN_NULL_NPC","face":"UNIT_IDLE"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"AGENT_GRONIA_NULL_NULL","text":{"KOREA":"그러게. 준법 정신이 생각보다 투철한가 봐.","JPN":"そうね。思ったより順法精神が徹底しているみたい。","ENG":"I know. I guess I am more compliant than I thought I’d be.","TWN":"是吧。可能是我的守法精神比較透徹。"},"stage":{"bg":"PROLOGUE_04","bgm":"THEMA_SECURITY_AGENT","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"MONTAGNE_ADMIN_NULL_NPC","text":{"KOREA":"내 눈앞에 있는 저 둘만 해치우면 가장 중요한 목표는 달성돼.","JPN":"目の前にいるあの二人さえやれば、一番大事な目標は達成される。","ENG":"If I get rid of the two standing in front of me, my most important objective will be complete.","TWN":"只要幹掉眼前的兩個人，就能達成我最重要的目標。"},"stage":{"bg":"PROLOGUE_04","bgm":"THEMA_SECURITY_AGENT","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"MONTAGNE_ADMIN_NULL_NPC","face":"UNIT_IDLE"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"MONTAGNE_ADMIN_NULL_NPC","text":{"KOREA":"나는 어차피 시한부 환자야. 이면세계를 표류하는 동안 광물질이 내 몸 속에서 자라나더군.","JPN":"私はしょせん死亡宣告を受けた身。裏世界を漂流するうちに、鉱物質が私の体内で増殖したらしい。","ENG":"I don’t have long for this world anyways. Minerals grew in my body while I was drifting along Counterside.","TWN":"反正我早就是個臨死的病人，在異界漂流的時候，我就發現身體裡開始生長一些微小的礦物了。"},"stage":{"bg":"PROLOGUE_04","bgm":"THEMA_SECURITY_AGENT","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"MONTAGNE_ADMIN_NULL_NPC","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"AGENT_GRONIA_NULL_NULL","text":{"KOREA":"무기 내려. 마지막 경고야.","JPN":"武器を下ろして。最後の警告よ。","ENG":"Drop your weapon. This is your last warning.","TWN":"放下武器。這是最後的警告。"},"stage":{"bg":"PROLOGUE_04","bgm":"THEMA_SECURITY_AGENT","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"AGENT_GRONIA_NULL_NULL","text":{"KOREA":"그렇게 복수하고 싶다면 차라리 다음 기회를 노려. 살아남는다면 다음이 있잖아.","JPN":"そんなに復讐したいなら、いっそ次のチャンスを狙って。生き延びたら次があるでしょう？","ENG":"If you want revenge so bad, you’d be better off waiting for a better chance. If you survive now, there could still be a next time.","TWN":"如果你真那麼想復仇，不如等下次機會？只有活下來才有機會。"},"stage":{"bg":"PROLOGUE_04","bgm":"THEMA_SECURITY_AGENT","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"MONTAGNE_ADMIN_NULL_NPC","text":{"KOREA":"왜? 가족 앞에서 손에 피 묻히기 무섭나?","JPN":"なぜ？　家族の前で手を汚すことが怖いのか？","ENG":"Why the hesitation? Are you scared to get your hands bloody in front of your family?","TWN":"為什麼？是害怕在家人面前沾上鮮血嗎？"},"stage":{"bg":"PROLOGUE_04","bgm":"THEMA_SECURITY_AGENT","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"MONTAGNE_ADMIN_NULL_NPC","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"AGENT_GRONIA_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"PROLOGUE_04","bgm":"THEMA_SECURITY_AGENT","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"MONTAGNE_ADMIN_NULL_NPC","text":{"KOREA":"오빠가 죽은 뒤로 목숨에 미련 따위 없었어.","JPN":"兄さんが死んで以来、命に未練なんてなかった。","ENG":"I had nothing on the table ever since my brother died.","TWN":"自從哥哥死後，我對這條生命已經毫無留戀了。"},"stage":{"bg":"PROLOGUE_04","bgm":"THEMA_SECURITY_AGENT","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"MONTAGNE_ADMIN_NULL_NPC","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"MONTAGNE_ADMIN_NULL_NPC","text":{"KOREA":"하다못해 내 죽음이 저들의 뇌리에 상처로 남을 수 있다면…….","JPN":"せめて私の死をあの者たちの脳裏に傷として残せるなら……","ENG":"If at the very least, my dying traumatizes them in some way...","TWN":"如果在死前，能給你們帶來痛苦……"},"stage":{"bg":"PROLOGUE_04","bgm":"THEMA_SECURITY_AGENT","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"MONTAGNE_ADMIN_NULL_NPC","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"AGENT_GRONIA_NULL_NULL","text":{"KOREA":"몽타뉴!","JPN":"モンターニュ！","ENG":"Montagne!","TWN":"蒙塔妮！"},"stage":{"bg":"PROLOGUE_04","bgm":"THEMA_SECURITY_AGENT","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"MONTAGNE_ADMIN_NULL_NPC","text":{"KOREA":"……기꺼이 버린다.","JPN":"……喜んで捨てる。","ENG":"...I would be willing to die now.","TWN":"……那我願意赴死。"},"stage":{"bg":"PROLOGUE_04","bgm":"THEMA_SECURITY_AGENT","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"MONTAGNE_ADMIN_NULL_NPC","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L11_1","type":"dialog","speaker":"AGENT_GRONIA_NULL_NULL","text":{"KOREA":"둘 다 눈 감아!!","JPN":"二人とも目を閉じて！！","ENG":"Both of you, close your eyes!!","TWN":"你們兩個閉上眼睛！！"},"stage":{"bg":"PROLOGUE_04","bgm":"THEMA_SECURITY_AGENT","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"MONTAGNE_ADMIN_NULL_NPC","text":{"KOREA":"……내 총을 쏴서 맞췄다고?","JPN":"……私の銃を撃ち落とした？","ENG":"...You shot my gun?","TWN":"……竟然射中我的槍？"},"stage":{"bg":"PROLOGUE_04","bgm":"THEMA_SECURITY_AGENT","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"MONTAGNE_ADMIN_NULL_NPC","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L18_1","type":"dialog","speaker":"AGENT_GRONIA_NULL_NULL","text":{"KOREA":"그래. 일생일대의 묘기였어.","JPN":"……そう。一世一代の神業ってところかな。","ENG":"Yup. It was the trick of a lifetime.","TWN":"怎麼樣？這可是世間少見的絕技。"},"stage":{"bg":"PROLOGUE_04","bgm":"THEMA_SECURITY_AGENT","filter":"NCFT_SEPIA","slots":{"L":{"char_id":"MONTAGNE_ADMIN_NULL_NPC","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L19_1","type":"dialog","speaker":"AGENT_GRONIA_NULL_NULL","text":{"KOREA":"손목은 당분간 쓰기 어렵겠지만, 목숨 값이라고 생각해.","JPN":"手首はしばらく使えないと思うけど、命拾いしたんだからいいでしょう。","ENG":"You won't be able to use your wrist for a while, but consider it a trade for your life.","TWN":"你的手腕可能暫時無法拿槍，就當作是保住性命的代價吧。"},"stage":{"bg":"PROLOGUE_04","bgm":"THEMA_SECURITY_AGENT","filter":"NCFT_SEPIA","slots":{"L":{"char_id":"MONTAGNE_ADMIN_NULL_NPC","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L20_1","type":"dialog","speaker":"MONTAGNE_ADMIN_NULL_NPC","text":{"KOREA":"어째서?","JPN":"なぜだ？","ENG":"But why?","TWN":"為什麼？"},"stage":{"bg":"PROLOGUE_04","bgm":"THEMA_SECURITY_AGENT","filter":"NCFT_SEPIA","slots":{"L":{"char_id":"MONTAGNE_ADMIN_NULL_NPC","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L21_1","type":"dialog","speaker":"MONTAGNE_ADMIN_NULL_NPC","text":{"KOREA":"날 살려서 감옥에 넣는다고 해 봤자 다른 형제들이 가만 있지 않을 거다.","JPN":"私を監獄に送ったところで他の兄弟たちが黙ってはいない。","ENG":"Even if you put me in jail alive, the other brothers won't sit still.","TWN":"就算你不殺我，把我關進監獄裡，其他兄弟也不會善罷甘休的。"},"stage":{"bg":"PROLOGUE_04","bgm":"THEMA_SECURITY_AGENT","filter":"NCFT_SEPIA","slots":{"L":{"char_id":"MONTAGNE_ADMIN_NULL_NPC","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L22_1","type":"dialog","speaker":"MONTAGNE_ADMIN_NULL_NPC","text":{"KOREA":"마에스트로의 소재를 알아내는 대로 죽여 버리겠지.","JPN":"マエストロの所在を吐き出させてから殺すだろう。","ENG":"As soon as they find out Maestra's location, they'll kill her.","TWN":"他們只要發現指揮家的下落，就會立刻動手。"},"stage":{"bg":"PROLOGUE_04","bgm":"THEMA_SECURITY_AGENT","filter":"NCFT_SEPIA","slots":{"L":{"char_id":"MONTAGNE_ADMIN_NULL_NPC","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L23_1","type":"dialog","speaker":"AGENT_GRONIA_NULL_NULL","text":{"KOREA":"그렇다면 신경 쓰이지 않게 적어도 내가 모르는 곳에서 죽어 줘.","JPN":"だったらせめてわからないように、私の見えないところで死んで。","ENG":"Then, at least die somewhere I won't be able to find you. So that it doesn't get on my conscience.","TWN":"那至少選在一個陌生的地方殺我吧。"},"stage":{"bg":"PROLOGUE_04","bgm":"THEMA_SECURITY_AGENT","filter":"NCFT_SEPIA","slots":{"L":{"char_id":"MONTAGNE_ADMIN_NULL_NPC","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L24_1","type":"dialog","speaker":"AGENT_GRONIA_NULL_NULL","text":{"KOREA":"내가 워낙 이리저리 쏘다니는 직업이라, 좋은 장소 찾으려면 한참 걸리겠지만.","JPN":"あちこち飛び回る仕事だから、そんな場所そう簡単には見つからないだろうけど。","ENG":"It'll take a while for you to find a suitable place, though, since my job takes me around the world.","TWN":"不過因為我的工作要求，時常會到處亂跑，光是要找地方可能就會花不少時間。"},"stage":{"bg":"PROLOGUE_04","bgm":"THEMA_SECURITY_AGENT","filter":"NCFT_SEPIA","slots":{"L":{"char_id":"MONTAGNE_ADMIN_NULL_NPC","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L25_1","type":"dialog","speaker":"MONTAGNE_ADMIN_NULL_NPC","text":{"KOREA":"웃기는군. 아무것도 모른다면서 죄책감이라도 느끼는 건가?","JPN":"おかしなことを言う。何も知らないと言ったくせに、罪悪感でも芽生えたか？","ENG":"Ha. You claim that you don't know anything, but you somehow feel guilty?","TWN":"笑死，明明說自己什麼都不知道，卻還是有罪惡感？"},"stage":{"bg":"PROLOGUE_04","bgm":"THEMA_SECURITY_AGENT","filter":"NCFT_SEPIA","slots":{"L":{"char_id":"MONTAGNE_ADMIN_NULL_NPC","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L29_1","type":"dialog","speaker":"AGENT_GRONIA_NULL_NULL","text":{"KOREA":"글쎄. 그냥……","JPN":"さあ、ただ……","ENG":"Well, it's just...","TWN":"不知道，只是……"},"stage":{"bg":"PROLOGUE_04","bgm":"THEMA_SECURITY_AGENT","filter":"NCFT_SEPIA","slots":{"L":{"char_id":"MONTAGNE_ADMIN_NULL_NPC","face":"UNIT_IDLE"},"C":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"AGENT_GRONIA_NULL_NULL","text":{"KOREA":"누가 피 흘리면서 죽어가는 꼴 보기도 지쳤거든.","JPN":"誰かが血を流して死んでいく様を見るのにも疲れちゃってね。","ENG":"I'm tired of watching people bleed and die.","TWN":"我再也不想見到有人在我面前流著血死去。"},"stage":{"bg":"PROLOGUE_04","bgm":"THEMA_SECURITY_AGENT","filter":"NCFT_SEPIA","slots":{"L":{"char_id":"MONTAGNE_ADMIN_NULL_NPC","face":"UNIT_IDLE"},"C":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"AGENT_GRONIA_NULL_NULL","text":{"KOREA":"이건 정답으로 부족할까?","JPN":"この答えじゃ不満？","ENG":"Is that a good enough of an answer?","TWN":"這個回答可以嗎？"},"stage":{"bg":"PROLOGUE_04","bgm":"THEMA_SECURITY_AGENT","filter":"NCFT_SEPIA","slots":{"L":{"char_id":"MONTAGNE_ADMIN_NULL_NPC","face":"UNIT_IDLE"},"C":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"MONTAGNE_ADMIN_NULL_NPC","text":{"KOREA":"……마음대로 생각해.","JPN":"……勝手にしろ。","ENG":"...Whatever.","TWN":"……你開心就好。"},"stage":{"bg":"PROLOGUE_04","bgm":"THEMA_SECURITY_AGENT","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"MONTAGNE_ADMIN_NULL_NPC","face":"UNIT_IDLE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"AGENT_GRONIA_NULL_NULL","text":{"KOREA":"결국 나는 안일한 여자야.","JPN":"結局私って甘いのよね。","ENG":"I'm just a complacent girl.","TWN":"結果我終究是一個安逸的女人。"},"stage":{"bg":"TRAIL","bgm":"THEMA_SECURITY_AGENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"AGENT_GRONIA_NULL_NULL","text":{"KOREA":"남에게나, 나 자신에게나.","JPN":"他人にも、自分にも。","ENG":"To others, and to myself.","TWN":"不管對其他人或是對自己都是。"},"stage":{"bg":"TRAIL","bgm":"THEMA_SECURITY_AGENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"AGENT_GRONIA_NULL_NULL","text":{"KOREA":"분명히 아직 덜 커서 그렇겠지. 사춘기일지도.","JPN":"きっとまだ大人になりきれていないせいね。思春期なのかも。","ENG":"It's definitely because I'm not all grown-up yet. Maybe I'm going through puberty.","TWN":"應該是因為還沒完全長大吧，可能還在青春期。"},"stage":{"bg":"TRAIL","bgm":"THEMA_SECURITY_AGENT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MONTAGNE_ADMIN_NULL_NPC","face":"UNIT_IDLE"}}}},{"id":"L40_1","type":"dialog","speaker":"AGENT_GRONIA_NULL_NULL","text":{"KOREA":"하지만 난 철두철미한 괴물보다 허술한 편이 더 마음에 들어.","JPN":"でも私は完全な化け物より、少し抜けている方が気に入っている。","ENG":"But I like being flawed more than being a complete monster.","TWN":"但比起變成一個扎扎實實的怪物，我更喜歡做一個馬馬虎虎的人類。"},"stage":{"bg":"TRAIL","bgm":"THEMA_SECURITY_AGENT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"MONTAGNE_ADMIN_NULL_NPC","face":"UNIT_IDLE"}}}},{"id":"L41_1","type":"dialog","speaker":"MONTAGNE_ADMIN_NULL_NPC","text":{"KOREA":"아니, 넌 분명 괴물이야. 내 앞에서 한가하게 그딴 소리나 지껄이는 걸 보면.","JPN":"いや、お前は紛れもない化け物だ。私の前でそんなことをぐだぐだと話せるんだから。","ENG":"No, you are undoubtedly a monster. Seeing how you're here talking about all that crap.","TWN":"不，你就是一個怪物。所以才會在我面前漫不經心地說著這些蠢話。"},"stage":{"bg":"TRAIL","bgm":"THEMA_SECURITY_AGENT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"MONTAGNE_ADMIN_NULL_NPC","face":"UNIT_IDLE"}}}},{"id":"L42_1","type":"dialog","speaker":"MONTAGNE_ADMIN_NULL_NPC","text":{"KOREA":"하지만…….","JPN":"でも……","ENG":"But...","TWN":"不過……"},"stage":{"bg":"TRAIL","bgm":"THEMA_SECURITY_AGENT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"MONTAGNE_ADMIN_NULL_NPC","face":"UNIT_IDLE"}}}},{"id":"L43_1","type":"dialog","speaker":"MONTAGNE_ADMIN_NULL_NPC","text":{"KOREA":"그래. 너나 나나 어른스럽지 못하군.","JPN":"大人になりきれていないのは私も同じだ。","ENG":"Yeah. Neither of us are very adult-like.","TWN":"沒錯，或許你和我都不夠成熟。"},"stage":{"bg":"TRAIL","bgm":"THEMA_SECURITY_AGENT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"MONTAGNE_ADMIN_NULL_NPC","face":"UNIT_IDLE"}}}},{"id":"L45_1","type":"dialog","speaker":"MONTAGNE_ADMIN_NULL_NPC","text":{"KOREA":"부디 가는 도중에 조용히 뒈지길 바란다. 마에스트로.","JPN":"どうかこの先の客車で静かにくたばってくれ。マエストロ。","ENG":"I hope you die a horrible and quiet death, Maestra.","TWN":"但願你會在路上安靜地死去，指揮家。"},"stage":{"bg":"TRAIL","bgm":"THEMA_SECURITY_AGENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MONTAGNE_ADMIN_NULL_NPC","face":"UNIT_IDLE"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"MONTAGNE_ADMIN_NULL_NPC","text":{"KOREA":"너는 괴물로서 모두에게 비난 받고 죽어야 세상에 이득이니까.","JPN":"世のため、お前は化け物としてみんなから非難されて死ぬべきだ。","ENG":"You'll be doing the world a favor once you die while everyone berates you as a monster.","TWN":"像你這種怪物，只有在眾人的唾棄中死去才會讓世界變得更美好。"},"stage":{"bg":"TRAIL","bgm":"THEMA_SECURITY_AGENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MONTAGNE_ADMIN_NULL_NPC","face":"UNIT_IDLE"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"AGENT_GRONIA_NULL_NULL","text":{"KOREA":"글쎄. 애국자 노릇은 네가 저지른 테러를 막은 뒤로 때려치워서.","JPN":"どうかな。愛国者のふりは君が引き起こしたテロ事件を阻止してからやめているからね。","ENG":"I don't know. I quit the whole acting-like-a-patriot thing after I stopped that terrorist attack you caused.","TWN":"這個嘛，上次阻止你的恐怖行動後，我就已經打消讓世界變得更美好的念頭了。"},"stage":{"bg":"TRAIL","bgm":"THEMA_SECURITY_AGENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"AGENT_GRONIA_NULL_NULL","text":{"KOREA":"술은 고마웠어.","JPN":"お酒、助かったわ。","ENG":"Thanks for the drink.","TWN":"謝謝你的酒。"},"stage":{"bg":"TRAIL","bgm":"THEMA_SECURITY_AGENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"AGENT_GRONIA_NULL_NULL","text":{"KOREA":"고마워, 몽타뉴.","JPN":"ありがとう、モンターニュ。","ENG":"Thank you, Montagne.","TWN":"謝謝你，蒙塔妮。"},"stage":{"bg":"TRAIL","bgm":"THEMA_SECURITY_AGENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"MONTAGNE_ADMIN_NULL_NPC","text":{"KOREA":"……가서 지옥에나 떨어져 버려.","JPN":"……早く地獄に落ちろ。","ENG":"...Go rot in hell.","TWN":"……快給我下地獄吧。"},"stage":{"bg":"TRAIL","bgm":"THEMA_SECURITY_AGENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MONTAGNE_ADMIN_NULL_NPC","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};